  ('dietitian-moex-11429', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列有關食物中毒時的處理法中，不正確者為： 保存食物中毒原因的食物殘留物  患者之嘔吐物及糞便要妥善保存 儘速向附近之警察機關報告   必要時應採取消毒隔離等措施', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "66a40bb85066", "answer_pdf_sha1": "ef42fcd1b56b", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11430', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '常見引起嬰兒肉毒桿菌中毒之食物為何？ 肉品  水果  牛奶  蜂蜜', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "66a40bb85066", "answer_pdf_sha1": "ef42fcd1b56b", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-11431', 'dietitian', 'dietitian-moex-093-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '下列有關仙人掌桿菌（Bacillus cereus）之敘述，不正確者為： 可形成內生孢子    通常存在於海產食品中 屬於格蘭氏陽性桿菌    會造成腹瀉型及嘔吐型的食物中毒症狀', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:59+00:00", "source_pdf_sha1": "66a40bb85066", "answer_pdf_sha1": "ef42fcd1b56b", "source_family": "moex-gov-tw", "moex": {"exam_code": "093020", "c": "112", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "食品衛生與安全", "year": "093", "exam_name": "093年第一次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
